const median = (xs: number[]): number => {
  const s = [...xs].sort((a, b) => a - b)
  const mid = Math.floor(s.length / 2)
  return s.length % 2 ? s[mid] : (s[mid - 1] + s[mid]) / 2
}

const cert = run(() => {
  const nonce = () => Math.random().toString(36).substring(2, 15);
  const name = `${__dirname}/localhost-${nonce()}`;

  // cross platform
  const args = [
    'req',
    '-x509',
    '-newkey',
    'rsa:4096',
    '-keyout',
    `${name}.key`,
    '-out',
    `${name}.crt`,
    '-days',
    '365',
    '-nodes',
    '-subj',
    '/CN=localhost',
    '-addext',
    'subjectAltName=DNS:localhost,IP:127.0.0.1',
  ];

  // Execute with proper argument handling
  childProcess.execFileSync('openssl', args, {
    stdio: 'ignore',
    windowsHide: true,
  });

  const key = fs.readFileSync(`${name}.key`);
  const cert = fs.readFileSync(`${name}.crt`);

  fs.unlinkSync(`${name}.key`);
  fs.unlinkSync(`${name}.crt`);

  return {
    key,
    cert,
  };
});

